Compiler explorer: https://godbolt.org/z/5Kvbqqjqd

```console
% cat a.c
int printf(const char *, ...);
int a = -6, b, c, e, f;
static unsigned char d;
short g;
static unsigned char *h = &d;
int *i = &b;
int j(int k) { return k << 2 & a; }
int main() {
  unsigned char **l[2];
  l[f] = &h;
  g = 4;
  for (; g != -15; g--) {
    *i = 0;
    c = 2;
    for (; j(10) - 40 + c >= -1; --c)
      ;
  }
  for (; c + *h + e != -1; ++e)
    ;
  printf("%d\n", e);
}
%
% clang -O0 a.c && ./a.out
1
% clang -O2 a.c && ./a.out
